function startLoginLockCountdown(seconds){
  var msg=document.getElementById('loginLockMsg');
  var cd=document.getElementById('loginLockCountdown');
  var btn=document.getElementById('loginSubmitBtn');
  if(msg)msg.style.display='block';
  if(btn)btn.disabled=true;
  var left=seconds;
  if(cd)cd.textContent=left;
  if(_loginLockTimer)clearInterval(_loginLockTimer);
  _loginLockTimer=setInterval(function(){
    left--;
    if(cd)cd.textContent=left;
    if(left<=0){
      clearInterval(_loginLockTimer);_loginLockTimer=null;
      if(msg)msg.style.display='none';
      if(btn)btn.disabled=false;
      _loginLockedUntil=0;
    }
  },1000);
}
