function openUiDialog(opts){opts=opts||{};var modal=document.getElementById('uiDialogModal');var title=document.getElementById('uiDialogTitle');var msg=document.getElementById('uiDialogMessage');var ok=document.getElementById('uiDialogOk');var cancel=document.getElementById('uiDialogCancel');var wrap=document.getElementById('uiDialogInputWrap');var input=document.getElementById('uiDialogInput');if(!modal||!title||!msg||!ok||!cancel||!wrap||!input){_nativeAlert(opts.message||'Hinweis');return Promise.resolve(opts.mode==='confirm'?false:(opts.mode==='prompt'?null:true))}uiDialogState.mode=opts.mode||'alert';title.textContent=opts.title||'Hinweis';msg.textContent=opts.message||'';ok.textContent=opts.okText||'OK';cancel.textContent=opts.cancelText||'Abbrechen';wrap.classList.toggle('hidden',uiDialogState.mode!=='prompt');cancel.style.display=uiDialogState.mode==='alert'?'none':'inline-flex';if(uiDialogState.mode==='prompt'){input.value=opts.defaultValue||'';input.placeholder=opts.placeholder||'';setTimeout(function(){input.focus();input.select()},10)}else setTimeout(function(){ok.focus()},10);modal.classList.add('active');return new Promise(function(resolve){uiDialogState.resolve=resolve})}
function uiAlert(message,title){return openUiDialog({mode:'alert',title:title||'Hinweis',message:String(message||'')})}
