function initUiDialog(){var ok=document.getElementById('uiDialogOk');var cancel=document.getElementById('uiDialogCancel');var modal=document.getElementById('uiDialogModal');var input=document.getElementById('uiDialogInput');if(ok){ok.onclick=function(){if(uiDialogState.mode==='confirm')closeUiDialog(true);else if(uiDialogState.mode==='prompt')closeUiDialog((input.value||'').trim());else closeUiDialog(true)}}if(cancel)cancel.onclick=function(){closeUiDialog(uiDialogState.mode==='confirm'?false:null)};if(modal)modal.onclick=function(e){if(e.target===modal)closeUiDialog(uiDialogState.mode==='confirm'?false:null)};document.addEventListener('keydown',function(e){if(!modal||!modal.classList.contains('active'))return;if(e.key==='Escape'){e.preventDefault();closeUiDialog(uiDialogState.mode==='confirm'?false:null)}if(e.key==='Enter'&&uiDialogState.mode!=='alert'){e.preventDefault();if(uiDialogState.mode==='confirm')closeUiDialog(true);if(uiDialogState.mode==='prompt')closeUiDialog((input.value||'').trim())}})}
