function buildInitialCompanySettingsForUser(u){var md=(u&&u.user_metadata)||{};return{firma:getCompanyNameFromUser(u),rechtsform:'',inhaber:md.owner_name||md.display_name||'',handelsregister:'',strasse:'',plz:'',ort:'',telefon:'',mobil:'',email:(u&&u.email)||'',website:'',steuernummer:'',ustId:'',kleinunternehmer:false,bank:'',iban:'',bic:'',defaultVat:0.19,zahlungsziel:14,invPrefix:'RE-',offerPrefix:'AN-',invFooterText:'',offerFooterText:'',offerMailSubject:'Angebot {{nummer}} von {{firma}}',offerMailBody:'',invoiceMailSubject:'Rechnung {{nummer}} von {{firma}}',invoiceMailBody:'',dunningFee1:5,dunningFee2:10,dunningFee3:15,dunningInterestRate:5,dunningWait2:7,dunningWait3:7,dunningMailSubject:'Mahnung {{stufe}} zu Rechnung {{nummer}} von {{firma}}',dunningMailBody:'',letterLayout:'modern',letterPrimary:'#0891b2',letterSecondary:'#0e7490',letterContentTop:50,letterheadPdfName:'',letterheadPdfImageDataUrl:'',logoDataUrl:''}}
async function handleLogin(e){
  e.preventDefault();
  var username=String((document.getElementById('loginUsername').value||'').trim()).toLowerCase();
  var password=document.getElementById('loginPassword').value;
  var errEl=document.getElementById('loginError');
  if(errEl)errEl.classList.add('hidden');
  if(isLocalMode()){
    try{
      var now=Date.now();
      if(_loginLockedUntil>now){startLoginLockCountdown(Math.ceil((_loginLockedUntil-now)/1000));return}
      try{await loadData({replace:true});}catch(e2){console.error('loadData failed:',e2)}
      ensureDefaultAdmin();
      var u=users.find(function(x){return String(x.username||'').toLowerCase()===username});
      var ok=false;
      if(u){
        if(u.passwordHash){ok=verifyPassword(password,u.passwordHash);}
        else{ok=(password==='admin'&&username==='admin')||(password===username);}
      }
      if(!ok||!u){
        _loginFailCount++;
        if(_loginFailCount>=5){_loginLockedUntil=Date.now()+30000;_loginFailCount=0;startLoginLockCountdown(30);return}
        if(errEl){errEl.textContent='Benutzername oder Passwort falsch';errEl.classList.remove('hidden')}
        return;
      }
      if(u.active===false){if(errEl){errEl.textContent='Dieser Benutzer ist deaktiviert.';errEl.classList.remove('hidden')}return}
      _loginFailCount=0;
      u.lastLogin=new Date().toISOString();
      currentUser={id:u.id,username:u.username,displayName:u.displayName||(u.firstName&&u.lastName?(u.firstName+' '+u.lastName):'Administrator'),role:u.role||'mitarbeiter',firstName:u.firstName||'',lastName:u.lastName||'',permissions:getPermissionsByRole(u.role||'mitarbeiter')};
      if(u.role==='admin'||u.role==='master')currentUser.permissions=getPermissionsByRole('admin');
      currentUserId=u.id;
      await saveData();
      showMainApp();
      if(!u.isSystem&&u.mustChangePassword){showMustChangePasswordModal();}
      return;
    }catch(errLocal){
      console.error('Login Fehler:',errLocal);
      if(errEl){errEl.textContent='Login-Fehler: '+String((errLocal&&errLocal.message)||errLocal||'Unbekannt');errEl.classList.remove('hidden')}
      return;
    }
  }
}
async function handleLogout(){
  if(!await uiConfirm('Wirklich abmelden?','Abmelden'))return;
  try{await saveData()}catch(e){}
  currentUser=null;currentUserId=null;
  document.getElementById('mainApp').style.display='none';
  document.getElementById('loginScreen').style.display='flex';
  var form=document.getElementById('loginForm');if(form)form.reset();
  var errEl=document.getElementById('loginError');if(errEl)errEl.classList.add('hidden');
}
function showMainApp(){
  var ls=document.getElementById('loginScreen');if(ls)ls.style.display='none';
  var ma=document.getElementById('mainApp');if(ma)ma.style.display='block';
  var role=currentUser?currentUser.role||'mitarbeiter':'mitarbeiter';
  var displayName=currentUser?(currentUser.displayName||currentUser.username||'Benutzer'):'Benutzer';
  var nameEl=document.getElementById('sidebarUserName');
  if(nameEl)nameEl.textContent=displayName;
  var roleEl=document.getElementById('sidebarUserRole');
  if(roleEl){roleEl.textContent=getRoleLabel(role);roleEl.className='wm-user-role-badge '+getRoleBadgeClass(role)}
  var avatarEl=document.getElementById('userAvatar');
  if(avatarEl){
    avatarEl.textContent=currentUser?getUserInitials(currentUser):'A';
    avatarEl.style.background=getUserAvatarColor(role);
  }
  var saa=document.getElementById('settingsAdminArea');if(saa)saa.style.display=(role==='admin'||role==='master')?'grid':'none';
  try{setSettingsTab(window.activeSettingsTab||'company')}catch(e){console.warn('setSettingsTab:',e)}
  try{applyPermissions()}catch(e){console.warn('applyPermissions:',e)}
  try{toggleMobileMoreMenu(false)}catch(e){console.warn('toggleMobileMoreMenu:',e)}
  try{setMobileActiveNav((document.querySelector('.app-section.active')||{}).id||'dashboard')}catch(e){console.warn('setMobileActiveNav:',e)}
  try{loadCompanySettings()}catch(e){console.warn('loadCompanySettings:',e)}
}
async function checkAuth(){
  if(isLocalMode()){
    try{await loadData({replace:true});}catch(e){console.error('loadData error:',e);}
    ensureDefaultAdmin();
    openAppLoginView();
    var fi=document.getElementById('loginFirmaName');
    if(fi)fi.textContent=companyData.firma||'Werkmeister Pro';
    var logo=document.getElementById('loginLogoImg');
    if(logo&&companyData.logoDataUrl)logo.src=companyData.logoDataUrl;
    return;
  }
}
function applyPermissions(){
  if(!currentUser)return;
  var role=currentUser.role||'mitarbeiter';
  var p=(role==='admin'||role==='master')?getPermissionsByRole('admin'):(currentUser.permissions||getPermissionsByRole(role));
  document.querySelectorAll('#mainNav .nav-item').forEach(function(i){var s=i.getAttribute('data-section');if(!s)return;i.classList.toggle('nav-hidden',!p[s])});
  var usersTabBtn=document.querySelector('[data-settings-tab-btn="users"]');
  if(usersTabBtn)usersTabBtn.style.display=(role==='admin'||role==='master')?'':'none';
  var emailTabBtn=document.getElementById('emailSettingsTabBtn');
  if(emailTabBtn)emailTabBtn.style.display=(role==='admin'||role==='master')?'':'none';
  var settingsNav=document.querySelector('#mainNav .nav-item[data-section="settings"]');
  if(settingsNav)settingsNav.classList.toggle('nav-hidden',!p.settings);
  renderMobileMoreMenu();syncMobilePrimaryNav();
}
