var _gsDrop=null,_gsInput=null,_gsActive=-1,_gsResults=[];
function _gsInit(){if(_gsDrop)return;_gsInput=document.getElementById('globalSearchInput');_gsDrop=document.getElementById('globalSearchDrop');document.addEventListener('mousedown',function(e){if(!document.getElementById('globalSearchBar').contains(e.target))globalSearchClose()},true)}
