function globalSearchKeydown(e){_gsInit();var items=_gsDrop?_gsDrop.querySelectorAll('.gsb-item'):[];if(e.key==='Escape'){globalSearchClose();_gsInput&&_gsInput.blur()}else if(e.key==='ArrowDown'){e.preventDefault();_gsActive=Math.min(_gsActive+1,items.length-1);_gsHighlight(items)}else if(e.key==='ArrowUp'){e.preventDefault();_gsActive=Math.max(_gsActive-1,0);_gsHighlight(items)}else if(e.key==='Enter'){if(_gsActive>=0&&items[_gsActive]){items[_gsActive].click()}}}
function _gsHighlight(items){items.forEach(function(el,i){el.style.background=i===_gsActive?'#e0f2fe':''})}
function _gsParseQuery(q){var r={raw:q,text:[],minAmt:-1,maxAmt:-1,months:[],year:-1,relDate:null,status:null,type:null};var s=q.toLowerCase();
// Type
if(/\brechnung(en)?\b/.test(s))r.type='invoice';else if(/\bauftrag([\u0308]e)?\b/.test(s))r.type='order';else if(/\bangebot(e)?\b/.test(s))r.type='offer';else if(/\bkunde[n]?\b/.test(s))r.type='customer';
// Status
if(/\boffen\b/.test(s))r.status='open';else if(/\bbezahlt\b/.test(s))r.status='paid';else if(/\b\u00fcberf[a\u00e4]llig\b/.test(s))r.status='overdue';
// Amount: zwischen X und Y
var mBetween=s.match(/zwischen\s+(\d+[\.,]?\d*)\s+und\s+(\d+[\.,]?\d*)/);
if(mBetween){r.minAmt=parseFloat(mBetween[1].replace(',','.'));r.maxAmt=parseFloat(mBetween[2].replace(',','.'))}
// Amount: über X
var mOver=s.match(/\b\u00fcber\s+(\d+[\.,]?\d*)/);if(mOver)r.minAmt=parseFloat(mOver[1].replace(',','.'));
// Amount: unter X
var mUnder=s.match(/\bunter\s+(\d+[\.,]?\d*)/);if(mUnder)r.maxAmt=parseFloat(mUnder[1].replace(',','.'));
// Amount: X Euro
var mEuro=s.match(/(\d+[\.,]?\d*)\s*euro/);if(mEuro&&r.minAmt<0&&r.maxAmt<0){var v=parseFloat(mEuro[1].replace(',','.'));r.minAmt=v*.8;r.maxAmt=v*1.2}
// Month names
var mNames=['januar','februar','m\u00e4rz','april','mai','juni','juli','august','september','oktober','november','dezember'];mNames.forEach(function(mn,mi){if(s.includes(mn))r.months.push(mi+1)});
// Relative date
if(s.includes('letzten monat')||s.includes('letztem monat'))r.relDate='lastmonth';else if(s.includes('dieses jahr'))r.relDate='thisyear';
// Year
var mYear=s.match(/\b(20\d\d)\b/);if(mYear)r.year=parseInt(mYear[1]);
// Clean text tokens (remove filter words)
var clean=q.replace(/zwischen\s+[\d.,]+\s+und\s+[\d.,]+/gi,'').replace(/[\u00fc]ber\s+[\d.,]+/gi,'').replace(/unter\s+[\d.,]+/gi,'').replace(/[\d.,]+\s*euro/gi,'').replace(/\b(rechnung(en)?|auftrag[\u0308]?e?|angebot(e)?|kunden?|offen|bezahlt|[\u00fc]berf[\u00e4a]llig|letzten?\s+monat|dieses\s+jahr|januar|februar|m[\u00e4a]rz|april|mai|juni|juli|august|september|oktober|november|dezember|20\d\d)\b/gi,'');r.text=clean.split(/\s+/).map(function(t){return t.trim().toLowerCase()}).filter(Boolean);
return r}
function _gsAmtMatch(p,amount){if(p.minAmt>=0&&amount<p.minAmt)return false;if(p.maxAmt>=0&&amount>p.maxAmt)return false;return true}
function _gsDateMatch(p,dateStr){if(!dateStr)return p.months.length===0&&p.year<0&&!p.relDate;var d=new Date(dateStr);if(isNaN(d))return true;var now=new Date();if(p.relDate==='lastmonth'){var lm=new Date(now.getFullYear(),now.getMonth()-1,1);return d.getFullYear()===lm.getFullYear()&&d.getMonth()===lm.getMonth()}if(p.relDate==='thisyear')return d.getFullYear()===now.getFullYear();if(p.year>0&&d.getFullYear()!==p.year)return false;if(p.months.length&&!p.months.includes(d.getMonth()+1))return false;return true}
function _gsTextMatch(tokens,fields){if(!tokens.length)return true;return tokens.every(function(t){return fields.some(function(f){return f&&String(f).toLowerCase().includes(t)})})}
function globalSearch(q){_gsInit();var cl=document.getElementById('globalSearchClear');if(cl)cl.style.display=q?'inline':'none';if(!q||!q.trim()){globalSearchClose();return}var p=_gsParseQuery(q);var today=new Date().toISOString().slice(0,10);var results={invoices:[],orders:[],offers:[],customers:[]};
// Rechnungen
if(!p.type||p.type==='invoice'){ensureArray(invoices).forEach(function(inv){if(!inv)return;var amt=Number(inv.grossTotal)||0;if(p.minAmt>=0||p.maxAmt>=0){if(!_gsAmtMatch(p,amt))return}if(!_gsDateMatch(p,inv.issueDate))return;if(p.status==='open'&&inv.status!=='draft'&&inv.status!=='finalized')return;if(p.status==='paid'&&inv.status!=='paid')return;if(p.status==='overdue'){if(inv.status==='paid')return;var due=inv.dueDate&&inv.dueDate!=='sofort'?inv.dueDate:'';if(!due||due>=today)return}var fields=[inv.number,inv.customer,inv.object,inv.status,fmtCur(amt),inv.issueDate];if(_gsTextMatch(p.text,fields))results.invoices.push(inv)})}
// Aufträge
if(!p.type||p.type==='order'){ensureArray(orders).forEach(function(o){if(!o)return;var svcs=ensureArray(o.services).filter(function(s){return s&&s.costType!=='prepayment'});var amt=svcs.reduce(function(a,s){if(s.costType==='position')return a+(Number(s.quantity)||0)*(Number(s.unitPrice)||0);var q=Number(s.quantity);if(!(q>0))q=1;var up=Number(s.unitPrice);var mc=Number(s.materialCost||0);if((!isFinite(up)||up<=0)&&mc>0)up=mc/q;var total=isFinite(mc)&&mc>0?mc:(q*up);return a+total},0);if(p.minAmt>=0||p.maxAmt>=0){if(!_gsAmtMatch(p,amt))return}if(!_gsDateMatch(p,o.date||o.createdAt))return;var svcTitles=svcs.map(function(s){return s.title||''}).join(' ');var fields=[o.customer,o.object,svcTitles,fmtCur(amt),o.date];if(_gsTextMatch(p.text,fields))results.orders.push({order:o,amt:amt})})}
// Angebote
if(!p.type||p.type==='offer'){ensureArray(offers).forEach(function(o){if(!o)return;var svcs=ensureArray(o.services).filter(function(s){return s&&s.costType!=='prepayment'});var amt=svcs.reduce(function(a,s){if(s.costType==='position')return a+(Number(s.quantity)||0)*(Number(s.unitPrice)||0);var q=Number(s.quantity);if(!(q>0))q=1;var up=Number(s.unitPrice);var mc=Number(s.materialCost||0);if((!isFinite(up)||up<=0)&&mc>0)up=mc/q;var total=isFinite(mc)&&mc>0?mc:(q*up);return a+total},0);if(p.minAmt>=0||p.maxAmt>=0){if(!_gsAmtMatch(p,amt))return}if(!_gsDateMatch(p,o.date||o.createdAt))return;if(p.status==='open'&&(o.offerStatus||'open')!=='open')return;if(p.status==='paid'&&o.offerStatus!=='accepted')return;var fields=[o.customer,o.object,fmtCur(amt),o.offerStatus,o.date];if(_gsTextMatch(p.text,fields))results.offers.push({offer:o,amt:amt})})}
// Kunden
if(!p.type||p.type==='customer'){if(p.minAmt<0&&p.maxAmt<0&&!p.months.length&&p.year<0&&!p.relDate&&!p.status){ensureArray(customers).forEach(function(c){if(!c)return;var fields=[c.company,c.firstName,c.lastName,c.street,c.zip,c.city,c.email,(c.firstName||'')+' '+(c.lastName||'')];if(_gsTextMatch(p.text,fields))results.customers.push(c)})}}
_gsRender(q,p,results)}
function _gsRender(q,p,results){_gsInit();var html='';var total=results.invoices.length+results.orders.length+results.offers.length+results.customers.length;if(!total){html='<div class="gsb-empty">Nichts gefunden f\u00fcr \u201e'+esc(q)+'\u201c<div class="gsb-empty-hint">Tipp: \u201eRechnung\u201c, \u201eAuftrag\u201c, \u201e\u00fcber 300\u201c, \u201eoffen\u201c, \u201eMai 2026\u201c</div></div>';_gsDrop.innerHTML=html;_gsDrop.classList.add('open');return}
// Rechnungen
if(results.invoices.length){var show=results.invoices.slice(0,5);html+='<div class="gsb-group-hd">&#128308; Rechnungen ('+results.invoices.length+')</div>';show.forEach(function(inv){var amt=Number(inv.grossTotal)||0;var sub=[inv.object,fmtCur(amt),inv.issueDate].filter(Boolean).join(' \u00b7 ');html+='<div class="gsb-item" onclick="globalSearchOpen(\'invoice\',\''+inv.id+'\')" tabindex="-1"><span class="gsb-badge gsb-badge-inv">RE</span><div class="gsb-item-body"><div class="gsb-item-title">'+esc(inv.number||'Entwurf')+' \u00b7 '+esc(inv.customer||'-')+'</div>'+(sub?'<div class="gsb-item-sub">'+esc(sub)+'</div>':'')+'</div></div>'});if(results.invoices.length>5)html+='<button class="gsb-more" onclick="globalSearchMore(\'invoices\')">'+results.invoices.length-5+' weitere Rechnungen \u2192</button>'}
// Aufträge
if(results.orders.length){var show2=results.orders.slice(0,5);html+='<div class="gsb-group-hd">&#128994; Auftr\u00e4ge ('+results.orders.length+')</div>';show2.forEach(function(r){var o=r.order;var sub=[o.object,fmtCur(r.amt),o.date].filter(Boolean).join(' \u00b7 ');html+='<div class="gsb-item" onclick="globalSearchOpen(\'order\',\''+o.id+'\')" tabindex="-1"><span class="gsb-badge gsb-badge-ord">AT</span><div class="gsb-item-body"><div class="gsb-item-title">'+esc(o.customer||'-')+'</div>'+(sub?'<div class="gsb-item-sub">'+esc(sub)+'</div>':'')+'</div></div>'});if(results.orders.length>5)html+='<button class="gsb-more" onclick="globalSearchMore(\'orders\')">'+results.orders.length-5+' weitere Auftr\u00e4ge \u2192</button>'}
// Angebote
if(results.offers.length){var show3=results.offers.slice(0,5);html+='<div class="gsb-group-hd">&#128993; Angebote ('+results.offers.length+')</div>';show3.forEach(function(r){var o=r.offer;var sub=[o.object,fmtCur(r.amt),o.date].filter(Boolean).join(' \u00b7 ');html+='<div class="gsb-item" onclick="globalSearchOpen(\'offer\',\''+o.id+'\')" tabindex="-1"><span class="gsb-badge gsb-badge-off">AG</span><div class="gsb-item-body"><div class="gsb-item-title">'+esc(o.customer||'-')+'</div>'+(sub?'<div class="gsb-item-sub">'+esc(sub)+'</div>':'')+'</div></div>'});if(results.offers.length>5)html+='<button class="gsb-more" onclick="globalSearchMore(\'offers\')">'+results.offers.length-5+' weitere Angebote \u2192</button>'}
// Kunden
if(results.customers.length){var show4=results.customers.slice(0,5);html+='<div class="gsb-group-hd">&#128996; Kunden ('+results.customers.length+')</div>';show4.forEach(function(c){var name=([c.firstName,c.lastName].filter(Boolean).join(' ')||c.company||'-');var sub=[c.company&&(c.firstName||c.lastName)?c.company:null,[c.street,[c.zip,c.city].filter(Boolean).join(' ')].filter(Boolean).join(', ')].filter(Boolean).join(' \u00b7 ');html+='<div class="gsb-item" onclick="globalSearchOpen(\'customer\',\''+c.id+'\')" tabindex="-1"><span class="gsb-badge gsb-badge-cust">KD</span><div class="gsb-item-body"><div class="gsb-item-title">'+esc(name)+'</div>'+(sub?'<div class="gsb-item-sub">'+esc(sub)+'</div>':'')+'</div></div>'});if(results.customers.length>5)html+='<button class="gsb-more" onclick="globalSearchMore(\'customers\')">'+results.customers.length-5+' weitere Kunden \u2192</button>'}
_gsDrop.innerHTML=html;_gsDrop.classList.add('open')}
function globalSearchOpen(type,id){globalSearchClose();if(_gsInput)_gsInput.blur();
if(type==='invoice'){showSection('invoices');setTimeout(function(){openInvoiceDetailModal(id)},50)}
else if(type==='order'){showSection('orders');setTimeout(function(){openOrderDetailModal(id)},50)}
else if(type==='offer'){showSection('offers');setTimeout(function(){openOfferDetailModal(id)},50)}
else if(type==='customer'){showSection('customers');setTimeout(function(){var c=customers.find(function(x){return x.id===id});if(c)showCustomerModal(c)},50)}}
function globalSearchMore(section){globalSearchClose();showSection(section)}
