function showSection(id,evt){document.querySelectorAll('.app-section').forEach(function(s){s.classList.remove('active')});document.getElementById(id).classList.add('active');document.querySelectorAll('#mainNav .nav-item').forEach(function(i){i.classList.remove('active')});var n=evt&&evt.target?evt.target.closest('.nav-item'):null;if(n)n.classList.add('active');else document.querySelectorAll('#mainNav .nav-item').forEach(function(i){if(i.getAttribute('data-section')===id)i.classList.add('active')});document.getElementById('sidebar').classList.remove('mobile-open');document.getElementById('mobile-overlay').classList.remove('active');toggleMobileMoreMenu(false);setMobileActiveNav(id);if(id==='orders')renderOrders();if(id==='offers')renderOffers();if(id==='customers')renderCustomers();if(id==='articles')renderArticles();if(id==='invoices')renderInvoices();if(id==='expenses')renderExpenses();if(id==='dunning')renderDunning();if(id==='dashboard'){updateDashboard()}if(id==='appointments'){renderAppointments();updateApptStats()}if(id==='tax'){fillTaxYearSelect();renderTaxReport()}if(id==='settings'){renderUsers();setSettingsTab(window.activeSettingsTab||'company');if(isMaster()){loadAuditLog();renderAuditLog();updateGobdStats()}}}
function toggleSettingsPanel(id,btn){var body=document.getElementById(id);if(!body)return;var isOpen=!body.classList.contains('hidden');body.classList.toggle('hidden',isOpen);if(btn){btn.setAttribute('aria-expanded',isOpen?'false':'true');var icon=btn.querySelector('.settings-panel-icon');if(icon)icon.textContent=isOpen?'+':'-'}}
function setSettingsTab(tab){var next=String(tab||'company');window.activeSettingsTab=next;document.querySelectorAll('#settings .settings-tab-btn').forEach(function(btn){btn.classList.toggle('active',btn.getAttribute('data-settings-tab-btn')===next)});document.querySelectorAll('#settings .settings-tab-panel').forEach(function(panel){panel.classList.toggle('hidden',panel.getAttribute('data-settings-tab')!==next)});var gobdEl=document.getElementById('gobdMasterArea');if(gobdEl){gobdEl.style.display=(isMaster()&&next==='users')?'block':'none'}if(next==='datenpfad')loadDataPathDisplay()}
async function loadDataPathDisplay(){var el=document.getElementById('currentDataPath');if(!el)return;try{var p=window.electronAPI&&window.electronAPI.getDataPath?await window.electronAPI.getDataPath():'';el.textContent=p||'(Standardpfad: Dokumente/WerkmeisterPro/daten.json)'}catch(e){el.textContent='Unbekannt'}}
async function changeDataPath(){
if(!window.electronAPI||!window.electronAPI.showFolderDialog){alert('Nur im Electron-Modus verf\u00fcgbar.');return}
var resEl=document.getElementById('datenpfadResult');
if(resEl){resEl.className='mt-5';resEl.innerHTML='<div class="text-gray-500 text-sm">Ordner-Dialog wird ge\u00f6ffnet\u2026</div>'}
var dlg=await window.electronAPI.showFolderDialog();
if(!dlg||dlg.canceled||!dlg.filePaths||!dlg.filePaths.length){if(resEl)resEl.className='mt-5 hidden';return}
var folder=dlg.filePaths[0];
var res=await window.electronAPI.saveDataPath(folder);
if(!res||!res.ok){if(resEl){resEl.className='mt-5';resEl.innerHTML='<div class="bg-red-50 border border-red-200 rounded-xl p-4 text-red-700 text-sm"><strong>Fehler:</strong> '+esc(res&&res.error?res.error:'Unbekannter Fehler')+'</div>'}return}
loadDataPathDisplay();
var reloadedData=await window.electronAPI.loadData();
if(reloadedData){if(reloadedData.invoices)invoices=ensureArray(reloadedData.invoices);if(reloadedData.customers)customers=ensureArray(reloadedData.customers);if(reloadedData.orders)orders=ensureArray(reloadedData.orders).map(normalizeOrderServices);if(reloadedData.offers)offers=ensureArray(reloadedData.offers);if(reloadedData.articles)articles=ensureArray(reloadedData.articles);if(reloadedData.expenses)expenses=ensureArray(reloadedData.expenses);if(reloadedData.expenseDocuments)expenseDocuments=ensureArray(reloadedData.expenseDocuments);if(reloadedData.expenseLineItems)expenseLineItems=ensureArray(reloadedData.expenseLineItems);if(reloadedData.expenseExtractions)expenseExtractions=ensureArray(reloadedData.expenseExtractions);if(reloadedData.appointments)appointments=ensureArray(reloadedData.appointments);renderInvoices();renderCustomers();renderOrders();renderOffers();if(typeof renderExpenses==='function')renderExpenses();updateDashboard()}
if(resEl){resEl.className='mt-5';resEl.innerHTML='<div class="bg-green-50 border border-green-200 rounded-xl p-4"><div class="font-bold text-green-800 mb-1">&#10003; Datenpfad gespeichert</div><div class="font-mono text-sm text-green-700 break-all">'+esc(res.dataFile)+'</div>'+(res.copied?'<div class="text-xs text-gray-500 mt-2">Bestehende Daten wurden in den neuen Ordner kopiert.</div>':'<div class="text-xs text-gray-500 mt-2">Daten werden ab sofort aus diesem Ordner gelesen.</div>')+'</div>'}
}
async function selectGoogleDriveFolder(){if(!window.electronAPI||!window.electronAPI.showFolderDialog){alert('Nur im Electron-Modus verf\u00fcgbar.');return}var dlg=await window.electronAPI.showFolderDialog();if(!dlg||dlg.canceled||!dlg.filePaths||!dlg.filePaths.length)return;var el=document.getElementById('compGoogleDrivePath');if(el)el.value=dlg.filePaths[0]}
function bindLetterPreviewLive(){var f=document.getElementById('companyForm');if(!f)return;f.addEventListener('input',function(){renderLetterheadPreview()});f.addEventListener('change',function(){renderLetterheadPreview()})}
function toggleMobileMenu(){document.getElementById('sidebar').classList.toggle('mobile-open');document.getElementById('mobile-overlay').classList.toggle('active')}
function getMobileCoreSections(){return['dashboard','orders','invoices','customers']}
function setMobileActiveNav(section){var nav=document.getElementById('mobile-bottom-nav');if(!nav)return;var core=getMobileCoreSections();var isCore=core.indexOf(section)!==-1;nav.querySelectorAll('button[data-mobile-section]').forEach(function(btn){var s=btn.getAttribute('data-mobile-section');btn.classList.toggle('active',isCore?s===section:(s==='more'))})}
function syncMobilePrimaryNav(){var nav=document.getElementById('mobile-bottom-nav');if(!nav)return;var core=getMobileCoreSections();core.forEach(function(s){var btn=nav.querySelector('button[data-mobile-section="'+s+'"]');var navItem=document.querySelector('#mainNav .nav-item[data-section="'+s+'"]');if(btn)btn.classList.toggle('mobile-bottom-hidden',!navItem||navItem.classList.contains('nav-hidden'))})}
function openSectionFromMobile(section){toggleMobileMoreMenu(false);showSection(section)}
function renderMobileMoreMenu(){
  var wrap=document.getElementById('mobileMoreList');
  var nav=document.getElementById('mobile-bottom-nav');
  if(!wrap||!nav)return;
  var core=getMobileCoreSections();
  var items=Array.prototype.slice.call(document.querySelectorAll('#mainNav .nav-item')).filter(function(i){
    var s=i.getAttribute('data-section');
    return!!s&&!i.classList.contains('nav-hidden')&&core.indexOf(s)===-1
  });
  var hasLogout=!!currentUser;
  var html='';
  if(items.length){
    html+=items.map(function(i){
      var s=i.getAttribute('data-section');
      var ic=(i.querySelector('.nav-icon')||{}).innerHTML||'&#9679;';
      var tx=(i.querySelector('span:last-child')||{}).textContent||s;
      return'<button type="button" class="mobile-bottom-sheet-item" onclick="openSectionFromMobile(\''+esc(s)+'\')"><span class="mr-2">'+ic+'</span>'+esc(tx)+'</button>'
    }).join('')
  }else{
    if(!hasLogout)html='<p class="text-xs text-gray-500">Keine weiteren Funktionen verfügbar.</p>'
  }
  if(hasLogout){
    if(html&&html.indexOf('<button')!==-1)html+='<div class="mobile-bottom-sheet-tools"></div>';
    html+='<button type="button" class="mobile-bottom-sheet-item danger" onclick="handleLogout()"><span class="mr-2">&#9211;</span>Abmelden</button>'
  }
  wrap.innerHTML=html;
  var moreBtn=nav.querySelector('button[data-mobile-section="more"]');
  if(moreBtn)moreBtn.classList.toggle('mobile-bottom-hidden',!(items.length||hasLogout))
}
function toggleMobileMoreMenu(forceState){var sheet=document.getElementById('mobile-bottom-sheet');var back=document.getElementById('mobile-bottom-backdrop');if(!sheet||!back)return;var open=sheet.classList.contains('active');var next=(typeof forceState==='boolean')?forceState:!open;sheet.classList.toggle('active',next);back.classList.toggle('active',next)}
function normalizeOrderServices(o){if(!o.services||o.services._empty)o.services=[];else if(!Array.isArray(o.services))o.services=Object.values(o.services);if(!o.photos||typeof o.photos!=='object')o.photos={before:[],after:[]};if(!Array.isArray(o.photos.before))o.photos.before=[];if(!Array.isArray(o.photos.after))o.photos.after=[];o.photos.before=o.photos.before.map(function(p,i){if(typeof p==='string')return{id:'photo_old_'+i,name:'Foto',dataUrl:p,createdAt:Date.now()};if(!(p&&typeof p==='object'))return null;var x=Object.assign({},p);if(x.storagePath&&!x.url)x.url=getOrderPhotoPublicUrl(x.storagePath);return x}).filter(Boolean);o.photos.after=o.photos.after.map(function(p,i){if(typeof p==='string')return{id:'photo_old_'+i,name:'Foto',dataUrl:p,createdAt:Date.now()};if(!(p&&typeof p==='object'))return null;var x=Object.assign({},p);if(x.storagePath&&!x.url)x.url=getOrderPhotoPublicUrl(x.storagePath);return x}).filter(Boolean);return o}
function calcTotal(entity){var services=ensureArray(entity&&entity.services);return services.reduce(function(sum,s){if(!s)return sum;var costType=s.costType||'position';if(costType==='prepayment')return sum;if(costType==='position'){var q=Number(s.quantity)||0;var up=Number(s.unitPrice)||0;return sum+(q*up)}var q2=Number(s.quantity);if(!(q2>0))q2=1;var up2=Number(s.unitPrice);var mc=Number(s.materialCost||0);if((!isFinite(up2)||up2<=0)&&mc>0)up2=mc/q2;var total=isFinite(mc)&&mc>0?mc:(q2*up2);return sum+total},0)}
function fn(v){var n=Number(v)||0;return n.toLocaleString('de-DE',{minimumFractionDigits:2,maximumFractionDigits:2})}
function fmtCur(v){return fn(v)+' EUR'}
function fmtNum(v){return fn(v)}
function addAuditEntry(action,entityType,entityId,details){auditLog=ensureArray(auditLog);auditLog.unshift({id:'log_'+Date.now(),createdAt:Date.now(),action:action,entityType:entityType,entityId:entityId,details:details,user:(currentUser&&currentUser.displayName)||'System'});if(auditLog.length>200)auditLog=auditLog.slice(0,200);saveData()}
function loadAuditLog(){}
function esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;')}
function escAttr(s){return(s||'').replace(/"/g,'&quot;').replace(/'/g,'&#39;').replace(/</g,'&lt;')}
function doUpdate(){
  var devPath=document.getElementById('updateDevPath').value.trim();
  var prodPath=document.getElementById('updateProdPath').value.trim();
  var msgEl=document.getElementById('updateStatusMsg');
  if(!devPath||!prodPath){
    msgEl.style.display='block';
    msgEl.style.background='#fef2f2';
    msgEl.style.border='1px solid #fca5a5';
    msgEl.style.color='#991b1b';
    msgEl.textContent='Bitte beide Pfade eingeben.';
    return;
  }
  if(!window.electronAPI||!window.electronAPI.copyFile){
    msgEl.style.display='block';
    msgEl.style.background='#fef2f2';
    msgEl.style.border='1px solid #fca5a5';
    msgEl.style.color='#991b1b';
    msgEl.textContent='Update-Funktion nur in der Desktop-App verfügbar.';
    return;
  }
  var ok=window.electronAPI.copyFile(devPath,prodPath);
  msgEl.style.display='block';
  if(ok){
    msgEl.style.background='#f0fdf4';
    msgEl.style.border='1px solid #86efac';
    msgEl.style.color='#14532d';
    msgEl.textContent='✅ Update erfolgreich eingespielt! Starte das Produktionsprogramm neu.';
  } else {
    msgEl.style.background='#fef2f2';
    msgEl.style.border='1px solid #fca5a5';
    msgEl.style.color='#991b1b';
    msgEl.textContent='❌ Fehler beim Kopieren. Bitte Pfade prüfen.';
  }
}

function startApp(){
  currentUser={id:'local_user',email:'lokal@werkmeister.de',displayName:'Benutzer',role:'master',permissions:{dashboard:true,customers:true,articles:true,orders:true,offers:true,invoices:true,dunning:true,appointments:true,tax:true,settings:true}};
  currentUserId='local_user';
  document.getElementById('loginScreen').style.display='none';
  document.getElementById('mainApp').style.display='block';
  var nameEl=document.getElementById('sidebarUserName');if(nameEl)nameEl.textContent='Werkmeister Pro';
  var roleEl=document.getElementById('sidebarUserRole');if(roleEl)roleEl.textContent='Lokal';
  var avatarEl=document.getElementById('userAvatar');if(avatarEl)avatarEl.textContent='W';
  document.getElementById('settingsAdminArea').style.display='grid';
  setSettingsTab('company');applyPermissions();toggleMobileMoreMenu(false);loadCompanySettings();loadData({replace:true});
}
